/**
 * API Client
 * Handles all HTTP requests to backend
 */

import axios from 'axios';

const API_BASE = process.env.REACT_APP_API_URL || 'http://localhost:5000/api';

const client = axios.create({
  baseURL: API_BASE,
  headers: {
    'Content-Type': 'application/json',
  },
});

export const AreaAPI = {
  /**
   * Get list of all areas
   */
  listAreas: async () => {
    try {
      const response = await client.get('/areas');
      return response.data;
    } catch (error) {
      return { success: false, error: error.message };
    }
  },

  /**
   * Load a specific area
   */
  loadArea: async (areaName) => {
    try {
      const response = await client.get(`/areas/${areaName}`);
      return response.data;
    } catch (error) {
      return { success: false, error: error.message };
    }
  },

  /**
   * Create a new area
   */
  createArea: async (name, options = {}) => {
    try {
      const response = await client.post('/areas', {
        name,
        ...options,
      });
      return response.data;
    } catch (error) {
      return { success: false, error: error.message };
    }
  },

  /**
   * Save an area
   */
  saveArea: async (areaName, areaData) => {
    try {
      const response = await client.put(`/areas/${areaName}`, { areaData });
      return response.data;
    } catch (error) {
      return { success: false, error: error.message };
    }
  },

  /**
   * Delete an area
   */
  deleteArea: async (areaName) => {
    try {
      const response = await client.delete(`/areas/${areaName}`);
      return response.data;
    } catch (error) {
      return { success: false, error: error.message };
    }
  },
};

export const RoomAPI = {
  /**
   * Create a new room
   */
  createRoom: async (areaData, room) => {
    try {
      const response = await client.post('/rooms', { areaData, room });
      return response.data;
    } catch (error) {
      return { success: false, error: error.message };
    }
  },

  /**
   * Update a room
   */
  updateRoom: async (vnum, areaData, roomData) => {
    try {
      const response = await client.put(`/rooms/${vnum}`, { areaData, roomData });
      return response.data;
    } catch (error) {
      return { success: false, error: error.message };
    }
  },

  /**
   * Delete a room
   */
  deleteRoom: async (vnum, areaData) => {
    try {
      const response = await client.delete(`/rooms/${vnum}`, { data: { areaData } });
      return response.data;
    } catch (error) {
      return { success: false, error: error.message };
    }
  },

  /**
   * Add an exit to a room
   */
  addExit: async (vnum, areaData, exit) => {
    try {
      const response = await client.post(`/rooms/${vnum}/exits`, { areaData, exit });
      return response.data;
    } catch (error) {
      return { success: false, error: error.message };
    }
  },

  /**
   * Remove an exit from a room
   */
  removeExit: async (vnum, direction, areaData) => {
    try {
      const response = await client.delete(`/rooms/${vnum}/exits/${direction}`, {
        data: { areaData },
      });
      return response.data;
    } catch (error) {
      return { success: false, error: error.message };
    }
  },
};

export default client;
